"import sys\nimport asyncio\nimport certifi\nfrom motor.motor_asyncio import AsyncIOMotorClient\nfrom pymongo import MongoClient\nfrom dotenv import load_dotenv\nimport os\n\nload_dotenv()\nuri = os.getenv('MONGODB_URL')\n\nwith open('scripts/tls_test_output.txt', 'w', encoding='utf-8') as f:\n    def log(m):\n        f.write(m + '\\n')\n        f.flush()\n\n    log(f'Testing URI: {uri[:30]}...')\n\n    def test_sync():\n        try:\n            client = MongoClient(\n                uri,\n                tls=True,\n                tlsCAFile=certifi.where() \n            )\n            client.admin.command('ping')\n            log('Sync client connected successfully!')\n        except Exception as e:\n            log(f'Sync client failed: {e}')\n\n    async def test_async():\n        try:\n            client = AsyncIOMotorClient(\n                uri,\n                tls=True,\n                tlsCAFile=certifi.where(),\n                tlsAllowInvalidCertificates=True,\n                serverSelectionTimeoutMS=15000\n            )\n            await client.admin.command('ping')\n            log('Async client connected successfully!')\n        except Exception as e:\n            log(f'Async client failed: {e}')\n\n    log('--- Sync Test ---')\n    test_sync()\n    log('--- Async Test ---')\n    asyncio.run(test_async())\n"
